sql:
SELECT drawdown_id, reservoir_id 
FROM drawdown_periods
WHERE drawdown_percentage < -40;

SELECT reservoir_id, drawdown_percentage
FROM drawdown_periods
WHERE duration_days > 100;

external_knowledge:
- 'Guarding the waters' is a metaphor for active reservoirs, which are in service and operational;
- 'Health checkup' is a metaphor for last inspection, indicating the latest date when the reservoir was assessed for safety and functionality;
- A 'more than 5% decrease in water level' signifies a significant drawdown period, reflecting a notable reduction in water storage capacity.

sql:
SELECT d.cause, d.start_date, u.user_name
FROM drawdown_periods d
JOIN users u ON u.email = 'john.smith@example.com';

SELECT AVG(catchment_area)
FROM reservoirs
WHERE capacity = (SELECT MIN(capacity) FROM reservoirs) AND is_active = 1;

SELECT reservoirs.reservoir_name, water_levels.water_level
FROM reservoirs
LEFT JOIN water_levels ON reservoirs.reservoir_id = water_levels.reservoir_id;
